"""
MKT Original Commentary — Matthew chapters 11–12
Run: python3 scripts/zc-original-matthew-11-12.py

Source data used:
- data/interlinear/matthew.json
- data/translation/draft/mediating/matthew.json
- data/commentary/mkt-original/matthew.json (existing ch1-10 carried forward)

Key decisions in this range:
- 11:5: Isaiah 35:5-6 + 61:1 echoes in the messianic answer; the list is deliberate
  intertextual citation, not mere description of deeds
- 11:12: biazetai disputed (middle vs. passive; positive vs. negative violence);
  noted as debated without taking a side
- 11:19: sophia/ergōn — wisdom justified by deeds, not disciples; genitive autēs
  refers back to sophia
- 11:27: "Johannine thunderbolt" — the mutual knowledge saying is the most
  Johannine material in the synoptics; addressed as such
- 11:30: chrēstos rendered "kind/gracious" not merely "easy"
- 12:5: bebēlousin — priests render the Sabbath common (desecrate), yet are
  innocent; the argument works only if the temple overrides Sabbath
- 12:7: Hosea 6:6 quote (eleos, not thusia) — same quote as 9:13
- 12:28: pneuma theou vs. Luke's daktylos theou — noted as a Matthean choice
- 12:40: tria hēmera kai treis nyktas — Jonah typology applied to burial
- 12:50: poiōn to thelēma — present participle: ongoing doing defines the family
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MATTHEW = {
  "11": {
    "1": '<p><strong>kai egeneto hote etelesen ho Iēsous</strong> — and it happened when Jesus had finished (<em>etelesen</em> aorist of <em>teleō</em>: to complete, bring to an end) — this formula closes each of Matthew\'s five major discourse blocks (7:28; 11:1; 13:53; 19:1; 26:1). <em>Metebē ekeithen tou didaskein kai kēryssein en tais polesin autōn</em> — he departed from there to teach and proclaim in their cities: the discourse on mission (ch10) leads directly to missionary practice.</p>',
    "2": '<p><strong>ho de Iōannēs akousas en tō desmōtēriō ta erga tou Christou</strong> — John, hearing in prison the works of the Messiah (<em>ta erga tou Christou</em>: the deeds of the Christ — Matthew uses <em>Christou</em> here without the article, as a title) — <em>desmōtērion</em> (prison, place of binding): John is imprisoned by Herod Antipas (14:3), setting up the contrast between his confinement and the liberation Jesus is enacting through the miracle-list of v.5.</p>',
    "3": '<p><strong>su ei ho erchomenos ē heteron prosdokōmen</strong> — are you the coming one or should we expect another (<em>ho erchomenos</em>, the coming one — a technical title for the eschatological deliverer, rooted in Ps 118:26; Mal 3:1) — the question is not doubt but identification: John wants to know whether Jesus\'s ministry matches the coming one he proclaimed (3:11). <em>Prosdokōmen</em> present subjunctive: are we to keep waiting/expecting.</p>',
    "4": '<p><strong>poreuentes apangeilate Iōannē ha akouete kai blepete</strong> — go and report to John what you hear and see — the format echoes the prophetic pattern of Isa 29:18-19; 35:5-6; 61:1, where the messianic deliverer is identified by what he does rather than what he claims. The answer is exegetically dense: it presupposes John knows the prophetic texts and will recognize the list as the messianic inventory.</p>',
    "5": '<p><strong>typhloi anablepousin kai chōloi peripatousin</strong> — the blind receive sight and the lame walk — the six-item list (blind, lame, lepers, deaf, dead, poor) maps precisely onto Isa 35:5-6 (blind/deaf/lame) + Isa 61:1 (poor have good news proclaimed). <em>Nekroi egeirontai</em> (dead are raised): inserted between the deaf and the poor, surpassing both Isaiah sources. <em>Ptōchoi euangelizontai</em> — the poor have good news proclaimed (<em>euangelizō</em> passive: the same verb as Isa 61:1 LXX; the proclamation is itself the messianic act).</p>',
    "6": '<p><strong>makarios estin hos ean mē skandalisthē en emoi</strong> — blessed is whoever does not stumble on account of me (<em>skandalisthē</em> aorist passive subjunctive of <em>skandalizō</em>, the passive: "not be caused to stumble") — the Beatitude form applied not to a virtue but to a response to Jesus himself: the potential stumbling-block is his identity. The statement implicitly acknowledges that some do find him a stumbling-block — the response to his deeds divides (cf. Isa 8:14; 1 Pet 2:8).</p>',
    "7": '<p><strong>ti exēlthate eis tēn erēmon theasasthai</strong> — what did you go out into the wilderness to see (<em>theasasthai</em> aorist infinitive of <em>theaomai</em>, to gaze at, observe as a spectacle — a stronger, more deliberate looking than <em>blepō</em>) — <em>kalamon hypo anemou saleuomenon</em> (a reed being shaken by the wind): the question-and-dismissal format of vv.7-9 is rhetorical, eliminating two wrong answers before arriving at the right one. A wind-blown reed is a figure of fickleness; the crowd did not go out for something trivially unstable.</p>',
    "8": '<p><strong>anthrōpon en malakois hēmphiesmenon</strong> — a man clothed in soft/delicate garments (<em>malakos</em>, soft — used of clothing to mean fine, luxurious; used of persons to mean morally soft) — <em>idou hoi ta malaka phorountes en tois oikois tōn basileōn eisin</em> (those wearing soft things are in the houses of kings): John\'s clothing (camel hair, leather belt — 3:4) is the antithesis of <em>malaka</em>. The contrast locates John in the prophetic tradition, not the royal court.</p>',
    "9": '<p><strong>alla ti exēlthate idein, prophētēn</strong> — but what did you go out to see, a prophet? — <em>nai legō hymin kai perissoteron prophētou</em> (yes I tell you and more than a prophet: <em>perissoteron</em> comparative of <em>perissos</em>, exceeding): the double affirmation acknowledges John as prophet and then immediately surpasses the category. What makes John more than a prophet is revealed in v.10 — he is the messenger long expected.</p>',
    "10": '<p><strong>houtos estin peri hou gegraptai</strong> — this is the one about whom it is written (<em>gegraptai</em> perfect passive: it stands written, the perfect marking enduring scriptural authority) — the citation is a composite of Exod 23:20 LXX (<em>idou apostellō ton angelon mou</em>) and Mal 3:1 (<em>pros kataskeuasai tēn hodon sou emprosthen sou</em>). Matthew shifts Malachi\'s "before me" to "before you," applying the divine messenger-sending directly to Jesus. The combination identifies John as both the Exodus wilderness-guide and the Malachi forerunner.</p>',
    "11": '<p><strong>en gennētois gynaikōn</strong> — among those born of women (<em>gennētos gynaikōn</em>, a Semitic idiom for every human being, emphasizing creaturely humanity; cf. Job 14:1) — <em>meizōn Iōannou tou baptistou oudeis egēgertai</em> (no one greater has arisen — <em>egēgertai</em> perfect passive: has been raised up, by divine agency). <em>Ho de mikroteros en tē basileia tōn ouranōn meizōn autou estin</em> — the lesser in the kingdom of the heavens is greater than he: <em>mikroteros</em> comparative; the kingdom establishes a different greatness-scale than birth-among-women.</p>',
    "12": '<p><strong>hē basileia tōn ouranōn biazetai</strong> — the kingdom of the heavens is subjected to violence / forces its way / presses forward (<em>biazetai</em>: middle or passive of <em>biazō</em>, disputed; middle = "is advancing forcefully"; passive = "is being violated/seized") — <em>kai biastai harpazousin autēn</em> (and violent people are seizing it — <em>harpazō</em>, to seize, snatch): the verse is among Matthew\'s most debated. The range runs from "the kingdom forcefully advances and the forceful lay hold of it" (positive reading) to "the kingdom suffers violence and violent men assault it" (negative, applied to Herod/opposition to John/Jesus).</p>',
    "13": '<p><strong>pantes gar hoi prophētai kai ho nomos heōs Iōannou eprophēteusan</strong> — for all the Prophets and the Law prophesied until John — the unusual order (Prophets before Law) may be deliberate emphasis; the standard phrase was "the Law and the Prophets" (5:17; 7:12). <em>Heōs Iōannou</em> (until John): John marks the terminus of the prophetic age. This supports v.10 — John is not just a prophet but the endpoint of prophetic anticipation, beyond which the thing anticipated has arrived.</p>',
    "14": '<p><strong>kai ei thelete dexasthai</strong> — and if you are willing to receive it (<em>thelete</em> present: if you are presently willing — a conditional on receptivity) — <em>autos estin Ēlias ho mellōn erchesthai</em> (he himself is Elijah who is about to come). The identification is conditional: only for those willing to receive it. John does not share Elijah\'s manner but fills the Elijah function: a voice calling Israel to repentance before the day of the LORD (Mal 4:5).</p>',
    "15": '<p><strong>ho echōn ōta akouetō</strong> — the one having ears, let them hear — a formulaic call to attention (<em>akouetō</em> present imperative: begin/continue hearing), used in Matthew after weighty or paradoxical sayings (13:9,43). Its placement after the Elijah identification implies that this identification is hidden to casual listening but available to those who press into the implications of the prophetic texts.</p>',
    "16": '<p><strong>tini de homoiōsō tēn genean tautēn</strong> — to what shall I compare this generation (<em>homoiōsō</em> aorist subjunctive: the deliberative use) — <em>hē genea autē</em> (this generation): the term carries a moral/spiritual load in Matthew; it is the generation characterized by resistance to the kingdom. The comparison deploys a children\'s game parable: the generation refuses every mode of engagement — neither the celebratory invitation nor the penitential one.</p>',
    "17": '<p><strong>ēulēsamen hymin kai ouk ōrchēsasthe</strong> — we played the pipe for you and you did not dance — <em>ēulēsamen</em> aorist of <em>auleō</em> (to play the flute, a wedding/celebration instrument); <em>ōrchēsasthe</em> aorist of <em>orcheomai</em> (to dance): the wedding scenario. <em>Ethrēnēsamen kai ouk ekopsasthe</em> (we sang a dirge and you did not mourn — <em>thrēneō</em>, to sing a funeral lament; <em>koptomai</em>, to beat one\'s breast in mourning): the funeral scenario. Both modes are refused. The parable is about the generation\'s refusal to engage with either John or Jesus on any terms.</p>',
    "18": '<p><strong>ēlthen gar Iōannēs mēte esthiōn mēte pinōn</strong> — for John came neither eating nor drinking — the double <em>mēte...mēte</em> marks absolute abstinence: John\'s ascetic practice (3:4; 9:14) was extreme even by the standards of fasting disciples. <em>Kai legousin daimonion echei</em> (and they say: he has a demon): the accusation against John takes the form of a demonization of his abstinence — his refusal of normal social-food is explained as demonic possession rather than prophetic calling.</p>',
    "19": '<p><strong>ēlthen ho huios tou anthrōpou esthiōn kai pinōn</strong> — the Son of Man came eating and drinking — the contrast with John (v.18) is total: Jesus participates in normal meals and social eating. <em>Idou anthrōpos phagos kai oinopotēs</em> (Look, a glutton and a wine-drinker — <em>phagos</em>, glutton; <em>oinopotēs</em>, wine-drinker/drunkard): the slanders are the inverse of John\'s charge. <em>Edikaioōthē hē sophia apo tōn ergōn autēs</em> — wisdom was justified/vindicated by her deeds (<em>edikaioōthē</em> aorist passive: stands justified; Luke has "by her children"): the deeds of Jesus and John together are wisdom\'s self-vindication.</p>',
    "20": '<p><strong>tote ērxato oneidizein tas poleis</strong> — then he began to denounce the cities (<em>oneidizō</em>, to reproach, upbraid — a strong word for public condemnation; used of mocking Jesus in 27:44) — <em>en hais egenonto hai pleistai dynameis autou</em> (in which most of his miracles had happened — <em>dynameis</em>, powers, mighty works): the denunciation is grounded in the specific history of miraculous witness. Greater exposure produces greater accountability; the woes follow the logic of vv.21-24.</p>',
    "21": '<p><strong>ouai soi, Chorazin, ouai soi, Bēthsaida</strong> — woe to you, Chorazin; woe to you, Bethsaida — <em>ouai</em> (woe) in prophetic discourse signals divine grief-and-judgment (cf. Isa 5:8-22). Chorazin and Bethsaida are not mentioned elsewhere as miracle-sites in Matthew, suggesting a wider tradition beyond what the Gospels record. <em>Tyrō kai Sidōni</em> (Tyre and Sidon): notorious Gentile cities condemned by the prophets (Isa 23; Ezek 26-28). That they would have repented in <em>sackcloth and ashes</em> (<em>sakkō kai spodō</em>, formal mourning posture) makes the Galilean failure more acute.</p>',
    "22": '<p><strong>plēn legō hymin Tyrō kai Sidōni anektoteron estai en hēmera kriseōs ē hymin</strong> — but I tell you, for Tyre and Sidon it will be more tolerable on the day of judgment than for you — <em>plēn</em> (but, however: a strong adversative); <em>anektoteron</em> (more bearable/tolerable: comparative, establishing a graduated scale of judgment). The judgment on Galilee is not the absence of judgment but its heightened form: having received more, more is required (cf. Luke 12:48).</p>',
    "23": '<p><strong>kai sy, Kapharnaoun, mē heōs ouranou hypsōthēsē</strong> — and you, Capernaum, will you be lifted to the heavens? (<em>hypsōthēsē</em> future passive of <em>hypsoō</em>) — <em>heōs haidou katabēsē</em> (you will descend to Hades — <em>katabēsē</em> future): the contrast echoes Isa 14:13-15 (the king of Babylon\'s boast of heavenly ascent followed by descent to Sheol). The allusion frames Capernaum\'s pride in its messianic privileges as Babel-arrogance. <em>Hoti ei en Sodomois egenēthēsan hai dynameis</em> — for if the miracles done in you had been done in Sodom, it would have remained to this day.</p>',
    "24": '<p><strong>plēn legō hymin hoti gē Sodomōn anektoteron estai en hēmera kriseōs ē soi</strong> — but I tell you that the land of Sodom will be more tolerable on judgment day than for you — Sodom, the paradigmatic city of destruction in Genesis 19, becomes the reference point by which Capernaum\'s guilt is measured. The logic mirrors vv.21-22: Gentile cities famous for wickedness face lighter judgment than Israelite cities that received the full witness of messianic miracles and rejected them.</p>',
    "25": '<p><strong>exomologoumai soi pater kyrie tou ouranou kai tēs gēs</strong> — I confess/praise you, Father, Lord of heaven and earth (<em>exomologeomai</em>: to acknowledge publicly, confess, or give praise; the word carries both confession and doxology) — <em>hoti apekrypsas tauta apo sophōn kai synetōn kai apekalypsas auta nēpiois</em> (because you hid these things from the wise and understanding and revealed them to little children — <em>nēpioi</em>: infants/little ones, not the spiritually mature but the socially insignificant): the prayer is Jesus\'s theological response to the cities\' rejection — the pattern of divine concealment-and-revelation explains what has just happened.</p>',
    "26": '<p><strong>nai ho patēr hoti houtōs eudokia egeneto emprosthen sou</strong> — yes, Father, because such was your good pleasure before you (<em>eudokia</em>, good pleasure, gracious purpose — from <em>eudokeō</em>, to be well-pleased; the same root as the voice at the baptism 3:17) — the verse repeats and affirms v.25 as a doxology. <em>Emprosthen sou</em> (before you, in your sight): the divine decision to conceal and reveal is not arbitrary but the expression of the Father\'s gracious pleasure.</p>',
    "27": '<p><strong>panta moi paredothē hypo tou patros mou</strong> — all things have been delivered to me by my Father (<em>paredothē</em> aorist passive of <em>paradidōmi</em>: to hand over, entrust — the same verb for handing over prisoners but here for positive transfer of authority) — <em>kai oudeis epiginōskei ton huion ei mē ho patēr</em> (and no one fully knows the Son except the Father — <em>epiginōskō</em>: intensive knowing, relational recognition). <em>Oude ton patera tis epiginōskei ei mē ho huios kai hō ean boulētai ho huios apokalypsai</em> — nor does anyone know the Father except the Son and whoever the Son chooses to reveal him to. This verse, often called the "Johannine thunderbolt," is the synoptic high-Christological statement: mutual, exclusive, intensive knowledge between Father and Son.</p>',
    "29": '<p><strong>arate ton zygon mou eph hymas kai mathete ap emou</strong> — take my yoke upon you and learn from me — <em>arate</em> aorist imperative of <em>airō</em>; <em>zygon</em> (yoke) is both the literal farming yoke and the rabbinic metaphor for Torah-obedience: "taking the yoke of the kingdom." <em>Mathete ap emou</em> (learn from me — <em>manthanō</em> aorist imperative: the root of <em>mathētēs</em>/disciple): Jesus invites discipleship to himself as teacher. <em>Hoti praus eimi kai tapeinos tē kardia</em> — for I am gentle and humble in heart: the only place in the Gospels where Jesus describes his own character in these specific terms. <em>Praus</em> (meek/gentle — the third Beatitude 5:5) and <em>tapeinos tē kardia</em> (humble in heart, not merely external humility).</p>',
    "30": '<p><strong>ho gar zygos mou chrēstos</strong> — for my yoke is kind/good (<em>chrēstos</em>: kind, gracious, pleasant, good in quality — the word used in 1 Pet 2:3 of God\'s goodness, quoting Ps 34:8; not merely "easy" in the sense of requiring little effort but "gracious" in character) — <em>kai to phortion mou elaphron estin</em> (and my burden is light — <em>elaphron</em>, light in weight; <em>phortion</em>, burden, load): the contrast with the Pharisees\' "heavy burdens" of 23:4 is implicit. The <em>chrēstos</em>/<em>elaphron</em> pair defines the quality of Jesus\'s yoke, not merely its quantity of demands.</p>'
  },
  "12": {
    "1": '<p><strong>en ekeinō tō kairō</strong> — in that season/time (<em>kairos</em>: a specific moment or season, not general time — <em>chronos</em>; this marks the Sabbath controversy as occurring within the theological moment of ch11\'s revelation/rejection discourse) — <em>epeinasan</em> (they were hungry — <em>peinaō</em> aorist: experienced hunger, the physical state that motivates the plucking): plucking grain by hand as a traveler was permitted under Deut 23:25; the controversy is about the day, not the act.</p>',
    "2": '<p><strong>hoi Pharisaioi idontes eipon autō</strong> — the Pharisees seeing said to him — <em>idou hoi mathētai sou poiousin ho ouk exestin poiein en sabbatō</em> (look, your disciples are doing what is not lawful to do on the Sabbath): the Pharisees address Jesus, not the disciples, establishing that the teacher bears responsibility for the disciples\' practice. <em>Ouk exestin</em> (it is not lawful): plucking was classified by some rabbinic schools as harvesting (<em>qatzir</em>), one of the 39 prohibited labors.</p>',
    "3": '<p><strong>ouk anegnōte ti epoiēsen Dauid</strong> — have you not read what David did (<em>anagnōte</em> aorist of <em>anaginōskō</em>: to read the Scriptures — Jesus challenges their knowledge of texts they claim to honor) — <em>hote epeinasen autos kai hoi met autou</em> (when he was hungry, he and those with him): hunger is the connecting term between the disciples\' situation and David\'s. The argument is a fortiori: if David\'s need justified setting aside the restriction on the showbread, the disciples\' need in the company of one greater than David (v.6) justifies their action.</p>',
    "4": '<p><strong>tous artous tēs prothēseōs</strong> — the bread of the presence/the showbread (<em>prothesis</em>, setting forth, display — the twelve loaves arranged on a special table in the sanctuary, Exod 25:30; Lev 24:5-9) — <em>ho ouk exōn ēn autō phagein</em> (which it was not lawful for him to eat — the same <em>ouk exōn</em> construction as the Pharisees\' charge in v.2): the argument uses their own legal category. <em>Ei mē tois hiereusin monois</em> (except for the priests alone): the OT reference is 1 Sam 21:1-6 (where Ahimelech the priest gives David the bread).</p>',
    "5": '<p><strong>hoi hiereis en tō hierō to sabbaton bebēlousin kai anaitioi eisin</strong> — the priests in the temple desecrate the Sabbath and are innocent (<em>bebēlousin</em> present of <em>bebēloō</em>, to make common, profane, desecrate — the root of the Fourth Commandment prohibition; the priests\' temple-work on Sabbath technically "makes it common" in legal terms) — <em>anaitioi eisin</em> (they are without guilt/innocent): priests performing sacrifices and temple duties on the Sabbath are not guilty because the temple service overrides the Sabbath restriction. The argument: if the temple overrides Sabbath, and something greater than the temple is here (v.6), it overrides the Sabbath too.</p>',
    "6": '<p><strong>legō de hymin hoti tou hierou meizon estin hōde</strong> — but I tell you that something greater than the temple is here (<em>meizon</em> neuter comparative: not "a greater one" — <em>meizōn</em> — but "something greater," making the reference to Jesus\'s presence indirect; Matthew uses the same neuter construction in v.41-42 for "greater than Jonah/Solomon") — the temple was the locus of the divine presence in Israel; to claim that something greater is present is to claim divine presence in a superior form.</p>',
    "7": '<p><strong>ei de egnōkeite ti estin eleos thelō kai ou thysian</strong> — if you had known what this means: I desire mercy and not sacrifice (<em>egnōkeite</em> pluperfect of <em>ginōskō</em>: if you had come to know — a condition of fact implying they had not) — the citation of Hos 6:6 is used also in 9:13. <em>Eleos</em> (mercy, loving-kindness — the LXX rendering of Hebrew <em>chesed</em>, covenant-loyalty). <em>Ou katediksate tous anaitious</em> — you would not have condemned the innocent: the Pharisees\' charge is not just legally mistaken but a violation of the very Scripture they uphold.</p>',
    "8": '<p><strong>kyrios gar estin tou sabbatou ho huios tou anthrōpou</strong> — for the Son of Man is Lord of the Sabbath (<em>kyrios tou sabbatou</em>: the genitive of possession/authority — Lord over the Sabbath as an institution) — the Sabbath was given by God at creation (Gen 2:2-3) and at Sinai (Exod 20:8-11). To be its Lord is to claim the authority of its Giver. The statement closes the Sabbath debate not with a legal ruling but with a Christological claim.</p>',
    "9": '<p><strong>kai metabas ekeithen ēlthen eis tēn synagōgēn autōn</strong> — and departing from there he came into their synagogue — <em>autōn</em> (their synagogue): the possessive pronoun marks increasing distance between Jesus and the Pharisees\' institutions; "their" recurs in v.14. The synagogue setting for the withered-hand healing places the second Sabbath controversy in the formal liturgical-judicial space of the Pharisees\' own domain, intensifying the confrontation.</p>',
    "10": '<p><strong>kai idou anthrōpos cheira echōn xēran</strong> — and behold a man having a withered hand (<em>xēra</em>, withered, dried up: the hand has lost function and vitality) — <em>kai epērōtēsan auton legontes</em> (and they asked him, saying — <em>epērōtaō</em> aorist: a formal inquiry): the Pharisees frame the question as a legal test: <em>ei exestin tois sabbasin therapeusai</em> (whether it is lawful to heal on the Sabbath). <em>Hina katēgorēsōsin autou</em> (in order to bring charges against him — <em>katēgoreō</em>: the courtroom verb for formal accusation).</p>',
    "11": '<p><strong>tis estai ex hymōn anthrōpos hos hexei probaton hen</strong> — which person among you who has a single sheep (<em>probaton hen</em>, one sheep — the singular emphasizes personal attachment) — <em>kai ean empesē touto tois sabbasin eis bothynon</em> (and if it falls into a pit on the Sabbath): rabbinic debates about rescuing animals on the Sabbath are attested in the Dead Sea Scrolls (CD 11:13-14 forbids it; later Pharisaic tradition may have permitted it). Jesus\'s question assumes the crowd would rescue the sheep, leveraging their instinctive compassion against rigid legal application.</p>',
    "12": '<p><strong>posō oun diapherei anthrōpos probatou</strong> — how much more valuable is a person than a sheep (<em>posō diapherei</em>: by how much does it differ — a qal wa-chomer/a fortiori argument: if sheep rescue is permissible, human healing is more so) — <em>hōste exestin tois sabbasin kalōs poiein</em> (so then it is lawful to do good on the Sabbath — <em>kalōs poiein</em>: to do good, do well): the positive formulation transcends the narrow "healing" question into a general principle of beneficence on the Sabbath.</p>',
    "13": '<p><strong>ekteison sou tēn cheira</strong> — stretch out your hand (<em>ekteison</em> aorist imperative of <em>ekteinō</em>, to stretch out) — <em>kai exeteinen</em> (and he stretched it out — the same verb; the action Jesus commands is itself part of the restoration): no spoken exorcism formula, just a command directed at the human body. <em>Kai apokatestathē hygiēs hōs hē allē</em> — and it was completely restored, as sound as the other (<em>apokatestathē</em> aorist passive of <em>apokathistēmi</em>: to restore to an original condition; the verb carries eschatological weight — the same root as <em>apokatastasis</em>, the restoration of all things).</p>',
    "14": '<p><strong>exelthontes de hoi Pharisaioi symboulion elabon kat autou</strong> — the Pharisees going out took counsel against him (<em>symboulion elabon</em>: took counsel, made a plan — the first explicit mention of a plot to kill Jesus in Matthew) — <em>hopōs auton apoleswōsin</em> (how they might destroy him — <em>apollymi</em> aorist subjunctive: the same word used for perishing/destruction, now directed at Jesus): the Sabbath healing that reveals Jesus\'s identity produces a death plot in the same scene.</p>',
    "15": '<p><strong>ho de Iēsous gnous anechōrēsen ekeithen</strong> — Jesus knowing withdrew from there (<em>gnous</em> aorist participle of <em>ginōskō</em>: knowing — perceptive knowledge of the plot; <em>anechōrēsen</em> aorist of <em>anachorew</em>: to withdraw, retreat — used of deliberate strategic withdrawal in Matthew) — <em>kai ēkolouthēsan autō ochloi polloi</em> (and large crowds followed him): the withdrawal from the Pharisees does not diminish his following. <em>Kai etherapeuse autous pantas</em> (and he healed them all — <em>pantas</em>, all, without selection).</p>',
    "16": '<p><strong>kai epetimēsen autois hina mē phaneron auton poiēsōsin</strong> — and he rebuked them so that they would not make him known (<em>epetimēsen</em> aorist of <em>epitimaō</em>, a strong rebuke — the same verb used for rebuking storms and demons; <em>hina mē phaneron auton poiēsōsin</em>: purpose clause, that they should not make him publicly visible) — the messianic secrecy command following mass healing sets up the Isaiah citation: Jesus\'s ministry matches the Servant\'s pattern of non-self-promotion.</p>',
    "17": '<p><strong>hina plērōthē to rēthen dia Ēsaiou tou prophētou legontos</strong> — in order that what was spoken through Isaiah the prophet might be fulfilled (<em>plērōthē</em> aorist passive subjunctive of <em>plēroō</em>: Matthew\'s fulfillment formula, used 11 times) — the citation formula introduces the longest OT citation in Matthew, covering Isa 42:1-4. Matthew\'s version differs from both the Hebrew MT and the LXX, suggesting either an independent translation or a Christian recension emphasizing specific elements of the Servant portrait.</p>',
    "18": '<p><strong>idou ho pais mou hon ēretisa</strong> — behold my servant whom I have chosen (<em>pais</em>: servant/child — the LXX word for the Isaian servant; <em>ēretisa</em>, aorist of <em>hairetizō</em>: to choose, elect — not the standard LXX term) — <em>ho agapētos mou eis hon eudokēsen hē psychē mou</em> (my beloved in whom my soul delights — <em>agapētos</em>: the same word as the baptismal/transfiguration voice; <em>eudokēsen</em> aorist of <em>eudokeō</em>: to be well-pleased): the language directly echoes the baptism (3:17) and transfiguration (17:5). <em>Thēsō to pneuma mou ep auton</em> — I will put my Spirit upon him (Isa 42:1).</p>',
    "19": '<p><strong>ouk erisei oude kraugasei</strong> — he will not quarrel nor cry aloud (<em>erizō</em>: to dispute, contend; <em>kraugazō</em>: to shout, cry out loudly) — <em>oude akousei tis en tais plateiais tēn phōnēn autou</em> (nor will anyone hear his voice in the streets): Matthew\'s version of Isa 42:2. The Servant\'s ministry is defined by absence of public self-assertion: no street-preaching for display, no competitive religious argument. This explains the secrecy command of v.16: Jesus follows the Servant\'s pattern of quiet, non-self-promoting action.</p>',
    "20": '<p><strong>kalamon syntetrimmenon ou kateaxei</strong> — a bruised reed he will not break (<em>syntetrimmenon</em> perfect passive participle of <em>syntribō</em>, to crush thoroughly: the reed is already crushed, not merely bent) — <em>kai linon typhomenon ou sbesei</em> (and a smoldering wick he will not extinguish — <em>typhomenon</em> present participle: actively smoldering; <em>sbesei</em> future): the Servant\'s work is not to eliminate the barely-surviving but to carry them through. <em>Heōs an ekbalē eis nikos tēn krisin</em> — until he brings justice through to victory (<em>nikos</em>, victory — stronger than the LXX\'s <em>alētheia</em>).</p>',
    "21": '<p><strong>kai tō onomati autou ethnē elpiousin</strong> — and in his name the nations will hope (<em>ethnē</em>, nations, Gentiles — not just Israel; the Servant\'s reach is explicitly universal) — Matthew\'s version follows neither MT nor LXX exactly: MT has "islands will wait for his law"; LXX and Matthew have "in his name nations will hope." The Gentile scope of the Servant\'s mission is important: at the point where the Pharisees plot to kill Jesus, the citation looks beyond Israel to the nations who will hope in his name.</p>',
    "22": '<p><strong>tote prosēnechthē autō daimonizomenos typhlos kai kōphos</strong> — then there was brought to him a demoniac who was blind and mute (<em>prosēnechthē</em> aorist passive: was brought — by others; <em>typhlos kai kōphos</em>: blind and mute, a double condition requiring a double healing) — <em>kai etherapeuse auton hōste ton kōphon lalein kai blepein</em> (and he healed him so that the mute man spoke and saw — <em>hōste</em> + infinitive: result clause): this miracle combines two of the messianic signs from 11:5, intensifying the Beelzeboul controversy that follows.</p>',
    "23": '<p><strong>kai existanto pantes hoi ochloi</strong> — and all the crowds were astonished (<em>existanto</em> imperfect of <em>existēmi</em>, to stand outside oneself, to be amazed — the response is ongoing, not a single moment) — <em>mēti houtos estin ho huios Dauid</em> (could this perhaps be the Son of David? — <em>mēti</em> introduces a cautious question expecting an uncertain answer: "Could this possibly be the Son of David?"): an open question, not a firm conclusion. The crowds wonder; the Pharisees (v.24) answer with an accusation.</p>',
    "24": '<p><strong>hoi de Pharisaioi akousantes eipon</strong> — but the Pharisees hearing said — <em>houtos ouk ekballei ta daimonia ei mē en tō Beelzeboul archonti tōn daimoniōn</em> (this man drives out demons only by Beelzeboul the ruler of demons): the accusation (first raised in 9:34) is escalated. <em>Beelzeboul</em>: the name-form in Matthew and Mark; probably from Baal-Zebul, "lord of the exalted house/dwelling." The logic: exorcism requires power over demons, which can come only from the demonic chain of command — unless the exorcist has a power that supersedes it.</p>',
    "25": '<p><strong>eidōs de tas enthymēseis autōn eipen autois</strong> — knowing their deliberations he said to them (<em>enthymēseis</em>: inner deliberations, used in 9:4 for the scribes\' inner reasoning about blasphemy) — <em>pasa basileia meristheisa kath heautēs erēmoutai</em> (every kingdom divided against itself is laid waste — <em>erēmoutai</em> present passive: is being deserted, becoming a wasteland): the three-part reductio (kingdom, city, household) applies a universal principle: internal division leads to collapse. If Jesus drives out demons by Satan, Satan is attacking his own forces.</p>',
    "26": '<p><strong>kai ei ho Satanas ton Satanan ekballei</strong> — and if Satan drives out Satan (<em>ekballei</em> present: the accusation applied directly as a hypothesis) — <em>eph heauton emeristhē</em> (he is divided against himself — <em>emeristhē</em> aorist passive): the logical impossibility stated as a completed action hypothetically. <em>Pōs oun stathēsetai hē basileia autou</em> (how then will his kingdom stand? — <em>stathēsetai</em> future passive of <em>histēmi</em>): the question is rhetorical; implied answer: it cannot.</p>',
    "27": '<p><strong>kai ei egō en Beelzeboul ekballō ta daimonia</strong> — and if I drive out demons by Beelzeboul — <em>hoi huioi hymōn en tini ekballousin</em> (by whom do your sons drive them out? — <em>hoi huioi hymōn</em>: your sons, your people — Jewish exorcists within the Pharisees\' own circles): the argument turns the accusation back. If the criterion is that exorcistic power implies demonic alliance, then Jewish exorcists are equally implicated. <em>Dia touto autoi kritai esontai hymōn</em> — therefore they will be your judges: the Jewish exorcists will testify against the Pharisees\' inconsistency.</p>',
    "28": '<p><strong>ei de en pneumati theou egō ekballō ta daimonia</strong> — but if it is by the Spirit of God that I drive out demons (<em>pneumati theou</em>: the Spirit of God — Matthew\'s version; Luke 11:20 has "finger of God," which may be the original Q form, echoing Exod 8:19) — <em>ara ephthasen eph hymas hē basileia tou theou</em> (then the kingdom of God has come upon you — <em>ephthasen</em> aorist of <em>phthanō</em>: to arrive before expected, to arrive already): the kingdom has come upon them without them recognizing it. Spirit-empowered exorcism is the presence of the eschatological kingdom, not a demonstration but the thing itself.</p>',
    "29": '<p><strong>ē pōs dynatai tis eiselthein eis tēn oikian tou ischyrou</strong> — or how can anyone enter the house of the strong man (<em>ischyros</em>, strong/powerful — the same word used in 3:11 for John\'s description of Jesus as "mightier than I") — <em>kai ta skeuē autou harpasai ean mē prōton dēsē ton ischyron</em> (and carry off his possessions unless he first binds the strong man — <em>dēsē</em> aorist subjunctive of <em>deō</em>: to bind): the parable defines Jesus\'s exorcistic ministry as the "binding" of Satan, making possible the rescue of those under his dominion. <em>Kai tote tēn oikian autou diarpasei</em> — and then he can plunder his house.</p>',
    "30": '<p><strong>ho mē ōn met emou kat emou estin</strong> — the one not with me is against me (<em>mē ōn met emou</em> present participle: the one who is not being with me, continuously not aligned) — <em>kai ho mē synagōn met emou skorpizei</em> (and the one not gathering with me is scattering — <em>skorpizei</em> present: is in the act of scattering): the gathering/scattering image recalls the shepherd (9:36; Ezek 34). No neutral position exists relative to Jesus\'s mission — not-gathering is actively scattering. This frames the Beelzeboul controversy: the Pharisees\' accusation is not neutral observation but active opposition.</p>',
    "32": '<p><strong>kai hos ean eipē logon kata tou huiou tou anthrōpou</strong> — and whoever speaks a word against the Son of Man (<em>logos kata</em>: a word directed against — the legal register) — <em>aphethēsetai autō</em> (it will be forgiven him — future passive divine): speech against Jesus-in-his-humiliation is forgivable. <em>Hos d an eipē kata tou pneumatos tou hagiou ouk aphethēsetai autō oute en toutō tō aiōni oute en tō mellonti</em> — whoever speaks against the Holy Spirit will not be forgiven, neither in this age nor in the age to come (<em>toutō tō aiōni...tō mellonti</em>: the two-age schema of Jewish eschatology; the Rabbinic <em>olam ha-zeh</em> and <em>olam ha-ba</em>).</p>',
    "33": '<p><strong>ē poiēsate to dendron kalon kai ton karpon autou kalon</strong> — either make the tree good and its fruit good (<em>poiēsate</em> aorist imperative of <em>poieō</em>: make, treat as — the command is logically ironic since one cannot simply make a tree good by willing it) — <em>ē poiēsate to dendron sapron kai ton karpon autou sapron</em> (or make the tree bad and its fruit bad — <em>sapros</em>: rotten, decayed): you must choose your category consistently. The Pharisees cannot attribute good fruit (healing) to a bad tree (demonic source). <em>Ek gar tou karpou to dendron ginōsketai</em> — for by the fruit the tree is known: the tree-fruit principle inverted from 7:16-20.</p>',
    "34": '<p><strong>gennēmata echidnōn</strong> — brood of vipers (<em>gennēmata echidnōn</em>: offspring of vipers — the same address as John\'s to the Pharisees and Sadducees in 3:7): the term combines origin and character. <em>Pōs dynasthe agatha lalein ponēroi ontes</em> (how are you able to say good things being evil? — <em>ponēroi ontes</em> present participle: constitutively evil): the Pharisees cannot produce good assessment because they are bad trees. <em>Ek gar tou perisseumatos tēs kardias to stoma lalei</em> — for the mouth speaks from the overflow of the heart (<em>perisseuma</em>: overflow, abundance — what pours over from a full container).</p>',
    "36": '<p><strong>pan rēma argon ho ean lalēsōsin hoi anthrōpoi</strong> — every idle/ineffective word that people speak (<em>rēma argon</em>: idle word — <em>argos</em> literally means not-working, inactive, idle; it can mean useless or irresponsible; in context, words spoken against the Spirit-empowered ministry of Jesus "do not work" because they misidentify what is happening) — <em>apodōsousin peri autou logon en hēmera kriseōs</em> (they will give an account about it on the day of judgment — <em>apodōsousin logon</em>: to render account, a judicial phrase).</p>',
    "37": '<p><strong>ek gar tōn logōn sou dikaiōthēsē</strong> — for by your words you will be justified/acquitted (<em>dikaiōthēsē</em> future passive of <em>dikaioō</em>: to be declared righteous, acquitted — the forensic term used here in a strict judicial sense: your words form the basis of the verdict) — <em>kai ek tōn logōn sou katadikasthēsē</em> (and by your words you will be condemned — <em>katadikasthēsē</em> future passive of <em>katadikō</em>): the forensic parallelism is exact. The speech-judgment principle addresses the fruits of the heart (v.34-35) that reveal what one truly is.</p>',
    "38": '<p><strong>tote apekrīthēsan autō tines tōn grammateōn kai Pharisaiōn</strong> — then some of the scribes and Pharisees answered him — <em>didaskale thelomen apo sou sēmeion idein</em> (teacher, we want to see a sign from you — <em>sēmeion</em>: a sign, a wonder-as-proof): the request for a sign follows the Beelzeboul controversy. Having explained away the miracles as demonic, they now request a different, unmistakable sign. <em>Thelomen</em> (we want): the verb of volition signals what drives the request — not openness to evidence but a demand for evidence on their own terms.</p>',
    "39": '<p><strong>genea ponēra kai moichalis sēmeion epizētei</strong> — a wicked and adulterous generation seeks a sign (<em>ponēra kai moichalis</em>: wicked and adulterous — <em>moichalis</em> is the prophetic term for covenant-unfaithfulness, Israel as an adulterous wife to YHWH; Hos 1-2; Jer 3:8; Ezek 16) — <em>kai sēmeion ou dothēsetai autē ei mē to sēmeion Iōna tou prophētou</em> (and a sign will not be given it except the sign of Jonah the prophet — <em>dothēsetai</em> future passive divine): the single exception is the Jonah-sign, which will not be recognized even when it comes.</p>',
    "40": '<p><strong>hōsper gar ēn Iōnas en tē koilia tou kētous treis hēmeras kai treis nyktas</strong> — for as Jonah was in the belly of the sea-monster three days and three nights (<em>kētos</em>: a great sea-creature; <em>treis hēmeras kai treis nyktas</em>: citing Jonah 1:17 LXX) — <em>houtōs estai ho huios tou anthrōpou en tē kardia tēs gēs treis hēmeras kai treis nyktas</em> (so will the Son of Man be in the heart of the earth — <em>en tē kardia tēs gēs</em>: the heart/center of the earth, echoing Ps 46:2; = burial): the Jonah typology applies not to Jonah\'s preaching but to his entombment and emergence. The only sign given is death and resurrection.</p>',
    "41": '<p><strong>andres Nineuitai anastēsontai en tē krisei meta tēs geneas tautēs kai katakrinousin autēn</strong> — the men of Nineveh will stand up at the judgment with this generation and condemn it (<em>anastēsontai</em> future of <em>anistēmi</em>: will rise up — the resurrection verb used for the judgment-rising of witnesses) — <em>hoti metenoēsan eis to kērygma Iōna</em> (for they repented at the preaching of Jonah — <em>metenoēsan</em> aorist: Nineveh\'s repentance was complete and definitive). <em>Kai idou pleion Iōna hōde</em> — and behold, something greater than Jonah is here: the neuter <em>pleion</em> (greater thing; cf. v.6,42) makes the comparison structural, not merely personal.</p>',
    "42": '<p><strong>basilissa notou egerthēsetai en tē krisei meta tēs geneas tautēs kai katakrinei autēn</strong> — the Queen of the South will rise at the judgment with this generation and condemn it (<em>basilissa notou</em>: the Queen of the South, the Queen of Sheba from 1 Kgs 10:1-13) — <em>hoti ēlthen ek tōn peratōn tēs gēs akousai tēn sophian Solomōntos</em> (for she came from the ends of the earth to hear the wisdom of Solomon — <em>peratōn tēs gēs</em>: the ends of the earth): a Gentile woman traveled the maximum distance to hear Israel\'s greatest king. <em>Kai idou pleion Solomōntos hōde</em> — and behold, something greater than Solomon is here.</p>',
    "43": '<p><strong>hotan de to akatharton pneuma exelthē apo tou anthrōpou</strong> — when the unclean spirit goes out of a person (<em>to akatharton pneuma</em>: the unclean spirit — <em>akatharton</em> is the ritual purity word applied to the spiritual realm) — <em>dierchetai di anydron topōn zētoun anapausin kai ouch heuriskei</em> (it passes through waterless places seeking rest and does not find it — <em>anydros</em>: waterless, arid; the wilderness/desert as the haunt of evil spirits is a Second Temple Jewish belief; <em>anapausin</em>: rest, the same word as 11:28-29): the returning-spirit parable addresses the generation\'s spiritual condition.</p>',
    "44": '<p><strong>tote legei eis ton oikon mou epistrepsō</strong> — then it says: I will return to my house (<em>epistrepsō</em> future: will return; the spirit claims the person as its "house") — <em>kai elthon heuriskei scholazonta sesarōmenon kai kekosmēmenon</em> (and coming it finds it standing empty, swept, and decorated — <em>scholazonta</em> present participle of <em>scholazō</em>: to be idle, empty, unoccupied; <em>sesarōmenon</em> perfect passive: having been swept; <em>kekosmēmenon</em> perfect passive: having been put in order/decorated): the danger is not the initial exorcism but the failure to fill the swept house. Empty order is not security.</p>',
    "45": '<p><strong>tote poreuetai kai paralambanei meth heautou hepta hetera pneumata ponērotera heautou</strong> — then it goes and takes with it seven other spirits more wicked than itself (<em>hepta</em>: seven, the number of completeness; <em>ponērotera</em> comparative: more evil) — <em>kai eiselthonta katoikei ekei</em> (and entering they dwell there — <em>katoikei</em> present: settled, permanent dwelling): the final state is quantitatively and qualitatively worse. <em>Kai ginetai ta eschata tou anthrōpou ekeinou cheirona tōn prōtōn</em> — and the last things of that person become worse than the first: <em>ta eschata</em> (last things, end condition) is eschatological vocabulary applied to the individual. <em>Houtōs estai kai tē genea tautē tē ponēra</em> — so also it will be with this wicked generation.</p>',
    "46": '<p><strong>eti de autou lalountos tois ochlois idou hē mētēr kai hoi adelphoi autou heistēkeisan exō</strong> — while he was still speaking to the crowds, behold his mother and brothers stood outside (<em>heistēkeisan</em> pluperfect of <em>histēmi</em>: had been standing — they were already there before this moment) — <em>zētountes autō lalēsai</em> (seeking to speak to him): the arrival of Jesus\'s biological family during a discourse on spiritual family creates the contrast that vv.48-50 resolve. The placement intercalates the physical family\'s interruption to allow the definition of the true family.</p>',
    "47": '<p><strong>eipen de tis autō</strong> — someone said to him — <em>idou hē mētēr sou kai hoi adelphoi sou exō hestēkasin zētountes soi lalēsai</em> (behold, your mother and your brothers are standing outside, seeking to speak to you): the messenger\'s message uses the natural kinship vocabulary (<em>hē mētēr sou kai hoi adelphoi sou</em>: your mother and your brothers) that Jesus is about to redefine. The verse is omitted in some manuscripts (Codex Sinaiticus) but has strong textual support and is parallel to Mark 3:32.</p>',
    "48": '<p><strong>ho de apokritheis eipen tō legonti autō</strong> — but he answering said to the one speaking to him — <em>tis estin hē mētēr mou kai tines eisin hoi adelphoi mou</em> (who is my mother and who are my brothers?): the rhetorical question is not a dismissal of Mary but a redefinition of the category "family." Jesus does not deny the biological family; instead he asks a question that opens the categories of <em>mētēr</em> (mother) and <em>adelphos</em> (brother) beyond biological definition to a new criterion.</p>',
    "49": '<p><strong>kai ekteinas tēn cheira autou epi tous mathētas autou eipen</strong> — and stretching out his hand toward his disciples he said (<em>ekteinas tēn cheira autou epi</em>: stretching out his hand toward — the same gesture-verb <em>ekteinō</em> used for healing the withered hand in v.13; here it is a gesture of identification) — <em>idou hē mētēr mou kai hoi adelphoi mou</em> (behold my mother and my brothers): the gesture makes the answer visible before the verbal declaration. The disciples present, not the family outside, constitute Jesus\'s nearest family.</p>',
    "50": '<p><strong>hostis gar an poiēsē to thelēma tou patros mou tou en ouranois</strong> — for whoever does the will of my Father in heaven (<em>poiēsē</em> aorist subjunctive of <em>poieō</em>: the general condition; <em>to thelēma tou patros mou</em>: the will of my Father, not the law abstractly but the Father\'s specific will) — <em>autos mou adelphos kai adelphē kai mētēr estin</em> (that person is my brother and sister and mother): the family-triad (brother, sister, mother) is now defined by the doing-of-will, not by birth. Father-will is the membership criterion for Jesus\'s family; the present continuous sense is implicit in the conditional construction.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'matthew')
    merge_comm(existing, MATTHEW)
    save_comm('mkt-original', 'matthew', existing)
    print('Matthew 11-12 mkt-original written.')

if __name__ == '__main__':
    main()
